var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"IRyS는 그녀의 시청자, IRyStocrats을 위해 직접 쓴 편지를 낭독하기로 했다.","JPN":"IRySは彼女のリスナー、IRyStocratsのために自筆の手紙を朗読すると決めた。","ENG":"IRyS decided to read a special letter that she has written for her loyal viewers, IRyStocrats.","TWN":"IRyS decided to read a special letter that she has written for her loyal viewers, IRyStocrats."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"곧, 그녀가 무대 뒤에 도착했다는 무전이 들려왔다.","JPN":"先ほど、彼女がバックステージに着いたとの連絡があった。","ENG":"Soon, a radio call arrived saying that she has arrived backstage.","TWN":"Soon, a radio call arrived saying that she has arrived backstage."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"흠흠. 예상대로 아직 남아있었네. 이번 방송도 마지막까지 봐줘서 고마워.","JPN":"フムフム。思ってたとおりまだいるね。今回の配信も最後まで見てくれてありがとう。 ","ENG":"Ahem. Oh, you're still here! Thanks for staying until the end of my stream. ","TWN":"Ahem. Oh, you're still here! Thanks for staying until the end of my stream. "},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_603"},{"id":"L9_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"아마 평소 같은 잡담을 기다렸겠지만... 미안. 오늘은 좀 색다른 걸 하려는데 괜찮으려나?","JPN":"たぶんいつもみたいなおしゃべりを聞こうと待ってたんだろうけど……ごめん。今日はちょっと変わったことをしようと思うんだけど、いい？","ENG":"You're probably expecting some casual chitchat like always... But sorry. I'm going to try out something different today.","TWN":"You're probably expecting some casual chitchat like always... But sorry. I'm going to try out something different today."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_604"},{"id":"L10_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"모처럼 널 위해 편지를 써 왔거든.","JPN":"あなたのために手紙を書いたんだ。","ENG":"I wrote a letter for you, actually.","TWN":"I wrote a letter for you, actually."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_605"},{"id":"L11_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"무슨 편지냐고? 그건 앞으로의 재미지. 궁금하면 집중해서 잘 들어줘.","JPN":"何の手紙かって？　それはこれからのお楽しみ。気になるなら集中してよく聞いてね。","ENG":"What kind of letter? That's for you to find out. Stay tuned if you're curious.","TWN":"What kind of letter? That's for you to find out. Stay tuned if you're curious."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_606"},{"id":"L12_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"..."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"HiRys~ It's IRyS!","JPN":"HiRys~ It's IRyS!","ENG":"HiRys~ It's IRyS!","TWN":"HiRys~ It's IRyS!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_607"},{"id":"L14_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"내 소중한 IRyStocrats.","JPN":"私の大切なIRyStocrats、聞いてる？ ","ENG":"To my dear IRyStocrats.","TWN":"To my dear IRyStocrats."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_608"},{"id":"L15_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"오늘 이 편지는 너에 대한 감사의 마음을 담은 거야.","JPN":"今日のこの手紙は、感謝の気持ちを込めて書いたの。","ENG":"This letter is my way of showing gratitude to you.","TWN":"This letter is my way of showing gratitude to you."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_609"},{"id":"L16_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"방송을 시작한 이후로, 네가 아니었다면 네거티브한 악마가 되어버렸을지도 모르는 순간이 종종 있었거든.","JPN":"配信を始めてから、あなたがいなかったらネガティブな悪魔になっちゃうかも～っていう時がよくあったからね。","ENG":"Ever since I started streaming, there were times when I would've ended up as a negative demon if it weren't for you.","TWN":"Ever since I started streaming, there were times when I would've ended up as a negative demon if it weren't for you."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_610"},{"id":"L17_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"고마워! 넌 모르겠지만, 불확실한 이중성이 튀어나올 때 네 말들은 정말 많은 도움이 돼.","JPN":"ありがと！　あなたは知らないと思うけど、不安定な二面性が出てくるとき、あなたの言葉に本当にいっぱい助けられてる。","ENG":"Thanks! You probably don't know, but your words help a lot when my unstable dual nature pops out.","TWN":"Thanks! You probably don't know, but your words help a lot when my unstable dual nature pops out."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_611"},{"id":"L18_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"네가 있기에 비로소 난 모두의 희망이 될 수 있었던 거지.","JPN":"あなたがいるから、私がみんなの希望になれたんだ。","ENG":"You're the reason I was able to become everyone's hope.","TWN":"You're the reason I was able to become everyone's hope."},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_612"},{"id":"L19_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"지금까지 그래왔던 것처럼, 앞으로도 계속 날 지켜봐 줘!","JPN":"いままでみたいに、これからもずっと私のこと見守ってね！","ENG":"So, I hope you keep watching as you have so far!","TWN":"So, I hope you keep watching as you have so far!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_613"},{"id":"L20_1","type":"dialog","speaker":"PUPPET_BLIND_CLB_003","text":{"KOREA":"…으으. 역시 직접 쓴 편지를 읽는 건 부끄럽네. 이렇게까지 했는데 다른 애로 갈아탄다고 하면 안 된다?","JPN":"……うう。やっぱり自分で書いた手紙を読むのって恥ずかしい。ここまでしたのに推し変するとか言ったら許さないからね？","ENG":"...Ngh. It's really embarrassing to read my own letter. I dare you to start following a different streamer after all this!","TWN":"...Ngh. It's really embarrassing to read my own letter. I dare you to start following a different streamer after all this!"},"stage":{"bg":"CLB_003","bgm":"COLLABO_2022_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_BLIND_CLB_003","face":"UNIT_DESPAIR"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_PUPPET_C_BLIND_CLB_003_LIFETIME_VOICE_614"}]`);export{e as default};